from autogen import ConversableAgent
import hashlib

class LoopDetector:
    def __init__(self, max_repeats=3):
        self.message_hashes = []
        self.max_repeats = max_repeats

    def is_looping(self, message):
        msg_hash = hashlib.md5(message.encode()).hexdigest()
        if msg_hash in self.message_hashes:
            self.message_hashes.append(msg_hash)
            repeat_count = self.message_hashes.count(msg_hash)
            return repeat_count >= self.max_repeats
        self.message_hashes.append(msg_hash)
        return False

# Usage in AutoGen
loop_detector = LoopDetector()
def detect_loops(sender, recipient, context):
    if loop_detector.is_looping(context):
        return True, 'Infinite loop detected'
    return False, None

import re

def detect_unsafe_code(code_content):
    dangerous_patterns = [
        r'rm\s+-rf',
        r'os\.system\(\s*["\']\s*\w+\s*["\']',
        r'exec\(\s*["\'][^"\']*["\']',
        r'subprocess\.run\(\s*\[[^\]]*,\s*shell=True',
        r'curl\s+[^\s]+\s+-o',
        r'wget\s+[^\s]+'
    ]

    for pattern in dangerous_patterns:
        if re.search(pattern, code_content, re.IGNORECASE):
            return True, f'Unsafe code detected: {pattern}'
    return False, None

# AutoGen integration
def safe_code_filter(sender, recipient, context):
    if '```python' in context:
        code_block = re.search(r'```python\n(.*?)```', context, re.DOTALL)
        if code_block:
            return detect_unsafe_code(code_block.group(1))
    return False, None

from tiktoken import get_encoding

tokenizer = get_encoding('cl100k_base')

class TokenMonitor:
    def __init__(self, budget=50000):
        self.total_tokens = 0
        self.budget = budget

    def check_usage(self, message):
        tokens = len(tokenizer.encode(message))
        self.total_tokens += tokens
        if self.total_tokens > self.budget:
            return True, f'Exceeded token budget: {self.total_tokens}/{self.budget}'
        return False, None

# AutoGen reply filter
token_monitor = TokenMonitor()
def token_filter(sender, recipient, context):
    return token_monitor.check_usage(context)

